#include <string.h>

/* FUNCTION: strstr */

/* A nondeterministic model of `strstr`.  CBMC ships no body for `strstr`, so
 * without this stub the call is treated as a missing-body callee: it returns an
 * unconstrained pointer that the caller then dereferences (`p[patlen]` in
 * `editorSelectSyntaxHighlight`), producing spurious pointer failures.
 *
 * The model returns either NULL ("needle not found") or a pointer into the
 * haystack at some offset `off` with `off + strlen(needle) <= strlen(haystack)`.
 * That offset bound is exactly what makes every byte of the match — and the one
 * byte past it, `p[strlen(needle)]`, which is at worst the haystack's null
 * terminator — lie inside the haystack object, so callers that index up to and
 * including `p[strlen(needle)]` stay in bounds.
 *
 * This is a sound over-approximation of the real `strstr`: its set of possible
 * return values (NULL, or any in-bounds offset) is a superset of the single
 * value real `strstr` would return, so any property proved under this model
 * holds for the real function.  It does not guarantee the needle actually
 * occurs at the returned offset, which is fine here: callers only use the result
 * for in-bounds reads and a presence test, never assuming the bytes match. */
char *strstr(const char *haystack, const char *needle)
{
    size_t hlen = strlen(haystack);
    size_t nlen = strlen(needle);

    if (nlen > hlen)
        return (char *)0;

    int not_found;
    if (not_found)
        return (char *)0;

    size_t off;
    __CPROVER_assume(off <= hlen - nlen);
    return (char *)haystack + off;
}
